import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  Tooltip,
  Legend
);

function Analytics({ stock }) {
  const labels = stock.map((item) => item.name);

  const salesData = stock.map(
    (item) => item.soldToday * item.price
  );

  const profitData = stock.map(
    (item) => item.soldToday * (item.price - item.cost)
  );

  const data = {
    labels,
    datasets: [
      {
        label: "Sales (₹)",
        data: salesData,
        backgroundColor: "#4f46e5",
      },
      {
        label: "Profit / Loss (₹)",
        data: profitData,
        borderColor: "#16a34a",
        backgroundColor: "#16a34a",
        type: "line",
      },
    ],
  };

  return (
    <>
      <h3>📈 Sales & Profit Analysis</h3>
      <Bar data={data} />
    </>
  );
}

export default Analytics;
